WITH src AS (SELECT id FROM ways_vertices_pgr WHERE id IN (SELECT source FROM ways WHERE cost IS NOT NULL) ORDER BY id LIMIT 1), tgt AS (SELECT id FROM ways_vertices_pgr WHERE id IN (SELECT source FROM ways WHERE cost IS NOT NULL) ORDER BY id OFFSET 100 LIMIT 1) SELECT * FROM pgr_dijkstra('SELECT id, source, target, CASE WHEN importance IN (1,2,3,4) THEN cost ELSE -1 END AS cost, CASE WHEN importance IN (1,2,3,4) THEN reverse_cost ELSE -1 END AS reverse_cost FROM ways', (SELECT id FROM src), (SELECT id FROM tgt), directed := true) LIMIT 5;
